import{_ as a,o as e,c as s,ag as d}from"./chunks/framework.DXGyWiRo.js";const c=JSON.parse('{"title":"1.2 集合的表示方法","description":"","frontmatter":{},"headers":[],"relativePath":"notes/gaozhong/gaoyi/chapter01-sets/1-2-集合的表示方法.md","filePath":"notes/gaozhong/gaoyi/chapter01-sets/1-2-集合的表示方法.md"}'),n={name:"notes/gaozhong/gaoyi/chapter01-sets/1-2-集合的表示方法.md"};function l(i,t,r,o,p,$){return e(),s("div",null,[...t[0]||(t[0]=[d('<h1 id="_1-2-集合的表示方法" tabindex="-1">1.2 集合的表示方法 <a class="header-anchor" href="#_1-2-集合的表示方法" aria-label="Permalink to &quot;1.2 集合的表示方法&quot;">​</a></h1><h2 id="一、列举法" tabindex="-1">一、列举法 <a class="header-anchor" href="#一、列举法" aria-label="Permalink to &quot;一、列举法&quot;">​</a></h2><p>将集合中的所有元素一一列举出来，写在大括号 {} 内。</p><p>$$A = {1, 2, 3, 4, 5}$$</p><p><strong>适用场景</strong>：元素个数有限且不多时。</p><div class="tip custom-block"><p class="custom-block-title">示例</p><ul><li>不大于 10 的正偶数：$B = {2, 4, 6, 8, 10}$</li><li>方程 $x^2 - 5x + 6 = 0$ 的解：$C = {2, 3}$</li></ul></div><h2 id="二、描述法" tabindex="-1">二、描述法 <a class="header-anchor" href="#二、描述法" aria-label="Permalink to &quot;二、描述法&quot;">​</a></h2><p>将集合中元素所具有的共同特征或满足的条件描述出来。</p><p>$$A = {x \\in \\mathbb{R} \\mid x^2 - 4 = 0}$$</p><p>解读：大括号内，竖线左侧写元素的一般形式，竖线右侧写元素满足的条件。</p><div class="tip custom-block"><p class="custom-block-title">示例</p><ul><li>不等式 $2x - 1 &gt; 3$ 的解：${x \\in \\mathbb{R} \\mid x &gt; 2}$</li><li>沪教版教材第 1-3 页例题：${x \\mid x \\text{ 是正方形}}$</li><li>方程 $x^2 = 9$ 的解：${x \\in \\mathbb{Z} \\mid x^2 = 9}$（整数解）</li></ul></div><h2 id="三、图示法-venn图" tabindex="-1">三、图示法（Venn图） <a class="header-anchor" href="#三、图示法-venn图" aria-label="Permalink to &quot;三、图示法（Venn图）&quot;">​</a></h2><p>用平面上一条封闭曲线的内部表示集合。</p><div class="tip custom-block"><p class="custom-block-title">示例</p><p>用 Venn 图表示集合 $A = {1, 2, 3}$：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>        ╭───────╮</span></span>\n<span class="line"><span>       ╱  1  2  ╲</span></span>\n<span class="line"><span>      │  3      │</span></span>\n<span class="line"><span>       ╲        ╱</span></span>\n<span class="line"><span>        ╰───────╯</span></span></code></pre></div></div><h2 id="四、区间表示法" tabindex="-1">四、区间表示法 <a class="header-anchor" href="#四、区间表示法" aria-label="Permalink to &quot;四、区间表示法&quot;">​</a></h2><p>用于表示数轴上连续的实数集合。</p><table tabindex="0"><thead><tr><th>写法</th><th>含义</th><th>数轴表示</th></tr></thead><tbody><tr><td>$(a, b)$</td><td>$a &lt; x &lt; b$</td><td>不含端点的线段</td></tr><tr><td>$[a, b]$</td><td>$a \\leqslant x \\leqslant b$</td><td>含端点的线段</td></tr><tr><td>$(a, b]$</td><td>$a &lt; x \\leqslant b$</td><td>左开右闭</td></tr><tr><td>$[a, b)$</td><td>$a \\leqslant x &lt; b$</td><td>左闭右开</td></tr><tr><td>$(a, +\\infty)$</td><td>$x &gt; a$</td><td>向右的射线</td></tr><tr><td>$(-\\infty, a]$</td><td>$x \\leqslant a$</td><td>向左的射线</td></tr></tbody></table><h2 id="五、自然语言与集合语言的转换" tabindex="-1">五、自然语言与集合语言的转换 <a class="header-anchor" href="#五、自然语言与集合语言的转换" aria-label="Permalink to &quot;五、自然语言与集合语言的转换&quot;">​</a></h2><table tabindex="0"><thead><tr><th>自然语言</th><th>集合语言</th></tr></thead><tbody><tr><td>$x$ 大于 3</td><td>$x &gt; 3$</td></tr><tr><td>$x$ 是正整数</td><td>$x \\in \\mathbb{N}^*$</td></tr><tr><td>$x$ 属于集合 $A$</td><td>$x \\in A$</td></tr><tr><td>$x$ 不小于 5</td><td>$x \\geqslant 5$</td></tr><tr><td>$x$ 在 2 和 10 之间</td><td>$2 &lt; x &lt; 10$</td></tr></tbody></table><h2 id="六、例题" tabindex="-1">六、例题 <a class="header-anchor" href="#六、例题" aria-label="Permalink to &quot;六、例题&quot;">​</a></h2><details class="details custom-block"><summary>点击查看例题</summary><p><strong>例1：</strong> 用两种方法表示&quot;绝对值小于 3 的整数&quot;。</p><p><strong>解析：</strong></p><p>列举法：${-2, -1, 0, 1, 2}$</p><p>描述法：${x \\in \\mathbb{Z} \\mid |x| &lt; 3}$</p><hr><p><strong>例2：</strong> 用区间表示 ${x \\in \\mathbb{R} \\mid -1 \\leqslant x &lt; 5}$，并在数轴上表示。</p><p><strong>解析：</strong></p><p>区间表示为 $[-1, 5)$。</p><p>数轴表示：●——————○（左端点实心，右端点空心）</p></details>',21)])])}const b=a(n,[["render",l]]);export{c as __pageData,b as default};
